const summary = $('Get Finance Summary').first().json;
const cashflow = $('Get Cashflow Forecast').first().json;
const netWorth = $('Get Net Worth').first().json;

const income = summary.total_income || 0;
const expenses = summary.total_expenses || 0;
const savings = summary.savings || 0;
const savingsRate = ((summary.savings_rate || 0) * 100).toFixed(1);
const netWorthValue = netWorth.net_worth_usd || 0;
const currentBalance = cashflow.current_balance || 0;

// Check for danger zones
const lowBalance = currentBalance < 500;
const negSavings = savings < 0;
const savingsRateLow = (summary.savings_rate || 0) < 0.1;

const fmtUSD = (n) => '$' + Math.abs(n).toLocaleString('en-US', {minimumFractionDigits: 0, maximumFractionDigits: 0});

let urgency = lowBalance || negSavings ? 'WARNING' : 'OK';
let lines = [];

lines.push(`*OvelhaInvest — Daily Finance Check*`);
lines.push(`${new Date().toLocaleDateString('en-US', {weekday: 'long', month: 'long', day: 'numeric'})}`);
lines.push('');
lines.push(`*This Month (${new Date().toLocaleDateString('en-US', {month: 'long', year: 'numeric'})})*`);
lines.push(`Income: ${fmtUSD(income)}`);
lines.push(`Expenses: ${fmtUSD(expenses)}`);
lines.push(`Net Savings: ${savings >= 0 ? '+' : ''}${fmtUSD(savings)}`);
lines.push(`Savings Rate: ${savingsRate}% ${savingsRateLow ? '(below 10% target)' : ''}`);
lines.push('');
lines.push(`*Balance & Net Worth*`);
lines.push(`Cash Balance: ${fmtUSD(currentBalance)} ${lowBalance ? '(LOW - below $500)' : ''}`);
lines.push(`Net Worth: ${fmtUSD(netWorthValue)}`);

if (urgency === 'WARNING') {
  lines.push('');
  lines.push('*Action Required:*');
  if (lowBalance) lines.push('- Cash balance is critically low (<$500). Review upcoming bills.');
  if (negSavings) lines.push('- Spending exceeds income this month. Review expenses.');
}

lines.push('');
lines.push('[View Finance Dashboard](https://invest.ovelha.us/finance)');

return [{json: {message: lines.join('\n'), urgency}}];
